import type { Novel } from '@/types';
import { stringifyError } from '@/utils/errors';
import { Card, Flex } from 'antd';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { NovelListItemCard } from '../NovelList/NovelListItemCard';

export const RecommendedNovelsCard: React.FC<{
  novelId: string;
}> = ({ novelId }) => {
  const [novels, setNovels] = useState<Novel[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>();

  useEffect(() => {
    let cancelled = false;
    const fetch = async () => {
      setLoading(true);
      setError(undefined);
      try {
        const { data } = await axios.get<Novel[]>(
          `/api/novel/${novelId}/recommended`
        );

        if (!cancelled) setNovels(data);
      } catch (err) {
        if (!cancelled) setError(stringifyError(err));
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    queueMicrotask(fetch);
    return () => {
      cancelled = true;
    };
  }, [novelId]);

  if (loading || error || !novels.length) {
    return null;
  }

  return (
    <Card
      title="Similar Novels"
      variant="outlined"
      styles={{ title: { fontSize: 20 } }}
    >
      <Flex gap={10} style={{ overflowY: 'visible', overflowX: 'auto' }}>
        {novels.map((novel) => (
          <div style={{ width: 165, flexShrink: 0, paddingTop: '4px 0' }}>
            <NovelListItemCard novel={novel} key={novel.id} />
          </div>
        ))}
      </Flex>
    </Card>
  );
};
