import { AddToLibraryButton } from '@/components/Library/AddToLibraryButton';
import { MakeArtifactModal } from '@/components/NovelActionPanel/MakeArtifactModal';
import { Auth } from '@/store/_auth';
import type { Job, LanguageCode, Novel, OutputFormat } from '@/types';
import { stringifyError } from '@/utils/errors';
import { BookOutlined, ExportOutlined } from '@ant-design/icons';
import { Col, message, Row } from 'antd';
import axios from 'axios';
import { useState } from 'react';
import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { ActionItem } from './ActionItem';
import { DeleteNovelButton } from './DeleteNovelButton';
import { SectionLabel } from './SectionLabel';

export const ManageSection: React.FC<{
  novel: Novel;
  language?: LanguageCode;
}> = ({ novel, language }) => {
  const navigate = useNavigate();
  const isAdmin = useSelector(Auth.select.isAdmin);
  const [messageApi, contextHolder] = message.useMessage();

  const [artifactModal, setArtifactModal] = useState(false);
  const [creatingArtifact, setCreatingArtifact] = useState(false);

  const handleMakeArtifact = async (formats: OutputFormat[]) => {
    if (!formats.length) {
      return messageApi.warning('Please select at least one format');
    }
    setArtifactModal(false);
    try {
      setCreatingArtifact(true);
      const result = await axios.post<Job>('/api/job/create/make-artifacts', {
        novel_id: novel.id,
        formats,
        language,
      });
      navigate(`/job/${result.data.id}`);
    } catch (err) {
      console.error(err);
      messageApi.error(stringifyError(err));
    } finally {
      setCreatingArtifact(false);
    }
  };

  return (
    <>
      {contextHolder}
      <SectionLabel>Manage</SectionLabel>
      <Row>
        <Col xs={24} sm={12} md={24} lg={12} xl={8}>
          <AddToLibraryButton
            novelId={novel.id}
            trigger={
              <ActionItem
                icon={<BookOutlined />}
                title="Add to Library"
                description="Save this novel to a library"
              />
            }
          />
        </Col>
        <Col xs={24} sm={12} md={24} lg={12} xl={8}>
          <ActionItem
            loading={creatingArtifact}
            icon={<ExportOutlined />}
            title="Make Artifact"
            onClick={() => setArtifactModal(true)}
            description="Generate artifacts in multiple formats"
          />
        </Col>
        {isAdmin && (
          <Col xs={24} sm={12} md={24} lg={12} xl={8}>
            <DeleteNovelButton novel={novel} />
          </Col>
        )}
      </Row>
      <MakeArtifactModal
        language={language}
        open={artifactModal}
        onClose={() => setArtifactModal(false)}
        onSelect={handleMakeArtifact}
      />
    </>
  );
};
