import { store } from '@/store';
import { Editor } from '@/store/_editor';
import type { Job, Novel, Volume } from '@/types';
import { stringifyError } from '@/utils/errors';
import {
  CloudDownloadOutlined,
  DownloadOutlined,
  SyncOutlined,
} from '@ant-design/icons';
import { Col, message, Row } from 'antd';
import axios from 'axios';
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ActionItem } from './ActionItem';
import { SectionLabel } from './SectionLabel';

export const FetchSection: React.FC<{ novel: Novel }> = ({ novel }) => {
  const navigate = useNavigate();
  const [messageApi, contextHolder] = message.useMessage();

  const [fetching, setFetching] = useState(false);
  const [fetchingFull, setFetchingFull] = useState(false);
  const [fetchingVolumes, setFetchingVolumes] = useState(false);

  const handleFetch = async (full: boolean) => {
    const setter = full ? setFetchingFull : setFetching;
    try {
      setter(true);
      store.dispatch(Editor.action.addNovelUrl(novel.url));
      const result = await axios.post<Job>('/api/job/create/fetch-novels', {
        urls: [novel.url],
        full,
      });
      navigate(`/job/${result.data.id}`);
    } catch (err) {
      messageApi.error(stringifyError(err));
    } finally {
      setter(false);
    }
  };

  const handleFetchAllVolumes = async () => {
    try {
      setFetchingVolumes(true);
      const { data: volumes } = await axios.get<Volume[]>(
        `/api/novel/${novel.id}/volumes`
      );
      const result = await axios.post<Job>('/api/job/create/fetch-volumes', {
        volumes: volumes.map((v) => v.id),
      });
      navigate(`/job/${result.data.id}`);
    } catch (err) {
      messageApi.error(stringifyError(err));
    } finally {
      setFetchingVolumes(false);
    }
  };

  return (
    <>
      {contextHolder}
      <SectionLabel>Fetch</SectionLabel>
      <Row>
        <Col xs={24} sm={12} md={24} lg={12} xl={8}>
          <ActionItem
            icon={<SyncOutlined />}
            title="Refresh Metadata"
            description="Update title, cover, synopsis, and chapter list"
            loading={fetching}
            onClick={() => handleFetch(false)}
          />
        </Col>
        <Col xs={24} sm={12} md={24} lg={12} xl={8}>
          <ActionItem
            icon={<CloudDownloadOutlined />}
            title="Fetch All Volumes"
            description="Download chapter content for all volumes"
            loading={fetchingVolumes}
            onClick={handleFetchAllVolumes}
          />
        </Col>
        <Col xs={24} sm={12} md={24} lg={12} xl={8}>
          <ActionItem
            icon={<DownloadOutlined />}
            title="Fetch Full Novel"
            description="Refresh metadata, fetch all volumes and make artifacts"
            loading={fetchingFull}
            onClick={() => handleFetch(true)}
          />
        </Col>
      </Row>
    </>
  );
};
