import { LoadingOutlined, RightOutlined } from '@ant-design/icons';
import { Flex, theme, Typography } from 'antd';
import { useState } from 'react';

export const ActionItem: React.FC<{
  icon: React.ReactNode;
  title: string;
  description: string;
  danger?: boolean;
  onClick?: () => void;
  loading?: boolean;
  extra?: React.ReactNode;
}> = ({ icon, title, description, danger, onClick, loading, extra }) => {
  const { token } = theme.useToken();
  const [hovered, setHovered] = useState(false);
  const isClickable = !!onClick && !loading;

  extra ??= <RightOutlined style={{ color: token.colorTextDisabled }} />;

  return (
    <Flex
      align="center"
      gap={10}
      style={{
        padding: '8px 12px',
        borderRadius: token.borderRadiusSM,
        cursor: isClickable ? 'pointer' : 'default',
        background:
          hovered && isClickable ? token.colorBgTextHover : 'transparent',
        transition: 'background 0.15s',
        opacity: loading ? 0.7 : 1,
      }}
      onClick={isClickable ? onClick : undefined}
      onMouseEnter={() => isClickable && setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div
        style={{
          fontSize: 17,
          width: 26,
          textAlign: 'center',
          flexShrink: 0,
          color: danger ? token.colorError : token.colorPrimary,
        }}
      >
        {loading ? <LoadingOutlined /> : icon}
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <Typography.Text
          strong
          style={{
            display: 'block',
            lineHeight: 1.35,
            fontSize: 13,
            color: danger ? token.colorError : undefined,
          }}
        >
          {title}
        </Typography.Text>
        <Typography.Text type="secondary" style={{ fontSize: 11 }}>
          {description}
        </Typography.Text>
      </div>
      {extra && (
        <div style={{ flexShrink: 0 }} onClick={(e) => e.stopPropagation()}>
          {extra}
        </div>
      )}
    </Flex>
  );
};
