import { type ReadHistory, type Volume } from '@/types';
import { LanguageCode } from '@/types/enums';
import { stringifyError } from '@/utils/errors';
import { Card, Collapse, Flex, message, Spin, Typography } from 'antd';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { VolumeDetailsCard } from './VolumeDetailsCard';

export const VolumeListCard: React.FC<{
  novelId: string;
  inner?: boolean;
  language?: LanguageCode;
}> = ({ novelId, inner, language }) => {
  const [messageApi, contextHolder] = message.useMessage();

  const [loading, setLoading] = useState<boolean>(true);
  const [volumes, setVolumes] = useState<Volume[]>([]);
  const [history, setHistory] = useState<ReadHistory>({});

  useEffect(() => {
    const fetchVolumes = async (id: string) => {
      setVolumes([]);
      setLoading(true);
      try {
        const { data: volumes } = await axios.get<Volume[]>(
          `/api/novel/${id}/volumes`,
          { params: language ? { language } : undefined }
        );
        setVolumes(volumes);
      } catch (err) {
        messageApi.error(stringifyError(err));
      } finally {
        setLoading(false);
      }
    };

    const fetchReadHistory = async (id: string) => {
      setHistory({});
      try {
        const { data: hisotry } = await axios.get<ReadHistory>(
          `/api/read-history/by-novel`,
          {
            params: {
              novel_id: id,
            },
          }
        );
        setHistory(hisotry);
      } catch (err) {
        messageApi.error(stringifyError(err));
      }
    };

    fetchVolumes(novelId);
    fetchReadHistory(novelId);
  }, [novelId, language, messageApi]);

  return (
    <Card
      type={inner ? 'inner' : undefined}
      title={!inner && 'Table of Contents'}
      variant={inner ? 'borderless' : 'outlined'}
      style={{ borderRadius: inner ? 0 : undefined }}
      styles={{
        body: { padding: 10 },
        title: { fontSize: 22 },
      }}
    >
      {contextHolder}

      {loading ? (
        <Flex align="center" justify="center">
          <Spin size="large" style={{ margin: '50px 0' }} />
        </Flex>
      ) : (
        <Collapse
          accordion
          defaultActiveKey={volumes[0]?.id}
          items={volumes.map((volume) => ({
            key: volume.id,
            label: volume.title,
            children: (
              <VolumeDetailsCard
                inner
                volume={volume}
                history={history}
                language={language}
              />
            ),
            extra: (
              <Typography.Text
                type="secondary"
                style={{ fontSize: '12px', whiteSpace: 'nowrap' }}
              >
                {Intl.NumberFormat('en').format(volume.chapter_count)} chapters
              </Typography.Text>
            ),
            styles: {
              body: { padding: 0 },
              header: { textTransform: 'capitalize' },
            },
          }))}
        />
      )}
    </Card>
  );
};
