import type { LanguageCode, Novel } from '@/types';
import { Card, Divider } from 'antd';
import { useParams } from 'react-router-dom';
import { FetchSection } from './FetchSection';
import { ManageSection } from './ManageSection';
import { TranslateSection } from './TranslateSection';

export const NovelActionsPanel: React.FC<{ novel: Novel }> = ({ novel }) => {
  const { language } = useParams<{ language?: LanguageCode }>();
  return (
    <Card title="Actions" styles={{ body: { padding: '6px 14px 10px' } }}>
      <FetchSection novel={novel} />
      <Divider style={{ margin: '4px 0' }} />
      <ManageSection novel={novel} language={language} />
      <Divider style={{ margin: '4px 0' }} />
      <TranslateSection novel={novel} />
    </Card>
  );
};
