import type { Novel } from '@/types';
import { stringifyError } from '@/utils/errors';
import { DeleteOutlined } from '@ant-design/icons';
import { message, Modal } from 'antd';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { ActionItem } from './ActionItem';

export const DeleteNovelButton: React.FC<{ novel: Novel }> = ({ novel }) => {
  const navigate = useNavigate();
  const [messageApi, contextHolder] = message.useMessage();
  const [modal, modalContextHolder] = Modal.useModal();

  const handleDelete = async () => {
    try {
      await axios.delete(`/api/novel/${novel.id}`);
      navigate('/novels');
    } catch (err) {
      messageApi.error(stringifyError(err));
    }
  };

  const handleDeleteConfirm = () => {
    modal.confirm({
      title: 'Delete this novel?',
      content:
        'This will permanently remove the novel and all associated data.',
      okText: 'Delete',
      okButtonProps: { danger: true },
      onOk: handleDelete,
    });
  };

  return (
    <>
      {contextHolder}
      {modalContextHolder}
      <ActionItem
        icon={<DeleteOutlined />}
        title="Delete Novel"
        description="Permanently remove this novel and all associated data"
        danger
        onClick={handleDeleteConfirm}
      />
    </>
  );
};
