import { OutputFormatTag } from '@/components/Tags/OutputFormatTag';
import { Auth } from '@/store/_auth';
import { LANGUAGE_LABELS, LanguageCode, OutputFormat } from '@/types';
import {
  AppstoreAddOutlined,
  CheckOutlined,
  PlusOutlined,
} from '@ant-design/icons';
import { Button, Col, Flex, Modal, Row, Typography } from 'antd';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { useSelector } from 'react-redux';

export const MakeArtifactModal: React.FC<{
  open: boolean;
  language?: LanguageCode;
  onClose: () => any;
  onSelect: (formats: OutputFormat[]) => any;
}> = ({ open, language, onClose, onSelect }) => {
  const authUser = useSelector(Auth.select.user);

  const [loading, setLoading] = useState(true);
  const [options, setOptions] = useState<OutputFormat[]>([]);
  const [selected, setSelected] = useState<Record<string, boolean>>({});

  const toggleSelected = (value: string) => {
    setSelected((p) => ({ ...p, [value]: !p[value] }));
  };

  useEffect(() => {
    const getEnabledFormats = async () => {
      setLoading(true);
      try {
        const result = await axios.get<string[]>(
          '/api/artifact/enabled-formats'
        );
        setOptions(result.data.sort());
      } catch {
        setOptions([OutputFormat.epub]);
      } finally {
        setLoading(false);
      }
    };
    getEnabledFormats();
  }, [authUser?.id]);

  return (
    <Modal
      width={400}
      open={open}
      loading={loading}
      okText="Create"
      onCancel={() => onClose()}
      onOk={() => onSelect(Object.keys(selected).filter((v) => selected[v]))}
      title={
        <Typography.Title level={4} style={{ margin: 0 }}>
          <AppstoreAddOutlined /> Make Artifact
          {language && <> ({LANGUAGE_LABELS[language]})</>}
        </Typography.Title>
      }
    >
      <Typography.Text
        type="secondary"
        style={{ marginBottom: 5, display: 'block' }}
      >
        Select the formats you want to create.
      </Typography.Text>

      <Row gutter={[6, 4]}>
        {options.map((value) => (
          <Col xs={12} key={value}>
            <Button
              block
              size="large"
              onClick={() => toggleSelected(value)}
              type={selected[value] ? 'primary' : 'default'}
              style={{
                borderRadius: 0,
                boxShadow: 'none',
                textAlign: 'left',
              }}
            >
              <Flex
                gap={6}
                align="center"
                justify="space-between"
                style={{ width: '100%' }}
              >
                <OutputFormatTag
                  noTooltip
                  value={value}
                  style={{
                    border: 'none',
                    fontSize: '0.9em',
                    background: 'transparent',
                  }}
                />
                {selected[value] ? <CheckOutlined /> : <PlusOutlined />}
              </Flex>
            </Button>
          </Col>
        ))}
      </Row>
    </Modal>
  );
};
