import type { Job, Novel } from '@/types';
import { LanguageCode } from '@/types/enums';
import { stringifyError } from '@/utils/errors';
import { BookOutlined, TranslationOutlined } from '@ant-design/icons';
import { Col, message, Row } from 'antd';
import axios from 'axios';
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ActionItem } from './ActionItem';
import { SectionLabel } from './SectionLabel';
import { LanguagePickerModal } from './LanguagePickerModal';

export const TranslateSection: React.FC<{ novel: Novel }> = ({ novel }) => {
  const navigate = useNavigate();
  const [messageApi, contextHolder] = message.useMessage();

  const [translating, setTranslating] = useState(false);
  const [translateModal, setTranslateModal] = useState<null | 'metadata' | 'full'>(null);

  const handleTranslate = async (full: boolean, lang: LanguageCode) => {
    setTranslateModal(null);
    try {
      setTranslating(true);
      const result = await axios.post<Job>('/api/job/create/translate-novels', {
        novel_ids: [novel.id],
        language: lang,
        full,
      });
      navigate(`/job/${result.data.id}`);
    } catch (err) {
      messageApi.error(stringifyError(err));
    } finally {
      setTranslating(false);
    }
  };

  return (
    <>
      {contextHolder}
      <SectionLabel>Translate</SectionLabel>
      <Row>
        <Col xs={24} sm={12} md={24} lg={12} xl={8}>
          <ActionItem
            icon={<TranslationOutlined />}
            title="Translate Metadata"
            description="Translate title, synopsis, and tags to a chosen language"
            loading={translating}
            onClick={() => setTranslateModal('metadata')}
          />
        </Col>
        <Col xs={24} sm={12} md={24} lg={12} xl={8}>
          <ActionItem
            icon={<BookOutlined />}
            title="Translate Full Novel"
            description="Translate all chapter content to a chosen language"
            loading={translating}
            onClick={() => setTranslateModal('full')}
          />
        </Col>
      </Row>
      <LanguagePickerModal
        open={!!translateModal}
        title={translateModal === 'full' ? 'Translate Full Novel' : 'Translate Metadata'}
        onSelect={(lang) => handleTranslate(translateModal === 'full', lang)}
        onClose={() => setTranslateModal(null)}
      />
    </>
  );
};
